using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Looks up a configuration value by key name.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'MaxRetries')")] string key)
    {
        var config = AppConfiguration.Current;
        return config.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("Lists all available configuration keys.")]
    public static string ListConfigKeys()
    {
        return string.Join("\n", AppConfiguration.Current.Keys.Order());
    }

    [McpServerTool, Description("Updates a configuration value. Returns the previous and new values.")]
    public static string SetConfigValue(
        [Description("The configuration key to update")] string key,
        [Description("The new value to set")] string value)
    {
        var config = AppConfiguration.Current;
        var had = config.TryGetValue(key, out var old);
        config[key] = value;

        return had
            ? $"Updated '{key}': '{old}' â†’ '{value}'"
            : $"Created '{key}' = '{value}'";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(
        UriTemplate = "config://app/all",
        Name = "Full App Configuration",
        MimeType = "application/json"),
     Description("Returns the complete application configuration as JSON.")]
    public static string GetAllConfig()
    {
        return JsonSerializer.Serialize(AppConfiguration.Current,
            new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(
        UriTemplate = "config://app/environment",
        Name = "Environment Info",
        MimeType = "application/json"),
     Description("Returns runtime environment information.")]
    public static string GetEnvironment()
    {
        var info = new
        {
            MachineName = Environment.MachineName,
            OsVersion = Environment.OSVersion.ToString(),
            DotNetVersion = Environment.Version.ToString(),
            ProcessId = Environment.ProcessId,
            Timestamp = DateTimeOffset.UtcNow
        };
        return JsonSerializer.Serialize(info,
            new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.Collections.Concurrent;

/// <summary>
/// Thread-safe in-memory configuration store shared by tools and resources.
/// </summary>
public static class AppConfiguration
{
    public static ConcurrentDictionary<string, string> Current { get; } = new(
        new Dictionary<string, string>
        {
            ["MaxRetries"] = "3",
            ["TimeoutSeconds"] = "30",
            ["LogLevel"] = "Information",
            ["FeatureFlags.DarkMode"] = "true",
            ["FeatureFlags.BetaApi"] = "false"
        });
}

